@namespace sv_c6e4e00e0d05474b9a7da4f03a564e02.Components.Pages.Settings
@using sv_c6e4e00e0d05474b9a7da4f03a564e02.Models

<div class="card">
    <div class="card-header">
        <h6 class="mb-0">Active Sessions</h6>
    </div>
    <div class="card-body p-0">
        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th class="text-end">Action</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                            <td class="text-end">
                                @if (session == Sessions.FirstOrDefault())
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

@* Confirmation dialog *@
@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke" disabled="@_revoking">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Revoke
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<ActiveSession> Sessions { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback<string> OnSessionRevoked { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        try
        {
            await OnSessionRevoked.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
        finally
        {
            _revoking = false;
        }
    }
}

