@namespace sv_c6e4e00e0d05474b9a7da4f03a564e02.Components.Pages.Settings
@using sv_c6e4e00e0d05474b9a7da4f03a564e02.Models

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <ChangePasswordPanel SettingsService="SettingsService" />

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Two-Factor Authentication</h6>
                <div class="d-flex align-items-center gap-3">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="twoFactor"
                               checked="@_twoFactorEnabled" disabled />
                        <label class="form-check-label" for="twoFactor">Two-Factor Authentication</label>
                    </div>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <small class="text-muted mt-2 d-block">
                        Last password change: @_lastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </small>
                }
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show mb-4" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <ActiveSessionsTable Sessions="_sessions" OnSessionRevoked="RevokeSessionAsync" />
    }
</div>

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        _message = null;
        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
            _message = "Session revoked successfully.";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to revoke session: {ex.Message}";
            _messageIsError = true;
        }
    }
}

@namespace sv_c6e4e00e0d05474b9a7da4f03a564e02.Components.Pages.Settings
@using sv_c6e4e00e0d05474b9a7da4f03a564e02.Models

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Theme</h6>
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check mb-2">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")"
                                       value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Font Size</h6>
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")"
                                       value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>
                </div>

                <div class="card mb-4">
                    <div class="card-body">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                    </div>
                </div>
            </div>

            <div class="col-md-5">
                <div class="card sticky-top" style="top: 1rem;">
                    <div class="card-header">
                        <h6 class="mb-0">Live Preview</h6>
                    </div>
                    <div class="card-body @PreviewBackgroundClass" style="@PreviewStyle">
                        <div class="@(_compactMode ? "mb-1" : "mb-3")">
                            <h6 class="@PreviewTextClass" style="@PreviewFontStyle">Dashboard Title</h6>
                        </div>
                        <p class="@PreviewTextClass" style="@PreviewFontStyle">
                            This is a preview of how your content will look with the selected settings.
                        </p>
                        <div class="d-flex gap-2 @(_compactMode ? "mt-1" : "mt-3")">
                            <button class="btn btn-sm btn-primary" style="@PreviewFontStyle">Primary</button>
                            <button class="btn btn-sm btn-outline-secondary" style="@PreviewFontStyle">Secondary</button>
                        </div>
                        <div class="@(_compactMode ? "mt-1" : "mt-3")">
                            <small class="@PreviewMutedClass" style="@PreviewFontStyle">
                                Theme: @_theme · Font: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")
                            </small>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary mt-2" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string PreviewBackgroundClass => _theme switch
    {
        "Dark" => "bg-dark",
        _ => "bg-light"
    };

    private string PreviewTextClass => _theme switch
    {
        "Dark" => "text-light",
        _ => "text-dark"
    };

    private string PreviewMutedClass => _theme switch
    {
        "Dark" => "text-light opacity-75",
        _ => "text-muted"
    };

    private string PreviewStyle => _theme switch
    {
        "Dark" => "border: 1px solid #444;",
        _ => ""
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.2rem;",
        _ => "font-size: 1rem;"
    };

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _message = "Appearance settings saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

