                    </span>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <small class="text-muted mt-2 d-block">
                        Last password change: @_lastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </small>
                }
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show mb-4" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <ActiveSessionsTable Sessions="_sessions" OnSessionRevoked="RevokeSessionAsync" />
    }
